// Aggregate today's reports
const reports = $input.all().map(i => i.json);

if (reports.length === 0) {
  return [{ json: { skip: true, reason: 'No reports today' } }];
}

// Flatten if nested array
const flat = Array.isArray(reports[0]) ? reports[0] : reports;

// Compute average score
const totalScore = flat.reduce((sum, r) => sum + (r.daily_eco_score || 0), 0);
const avgScore = (totalScore / flat.length).toFixed(1);

// Find top performer
const scoreboard = {};
for (const r of flat) {
  const phone = r.phone_number || 'unknown';
  scoreboard[phone] = (scoreboard[phone] || 0) + (r.daily_eco_score || 0);
}

let topPhone = null, topScore = -1;
for (const [phone, score] of Object.entries(scoreboard)) {
  if (score > topScore) { topScore = score; topPhone = phone; }
}

// Mask phone: +91-9876543210 → 987***210
const maskPhone = (p) => {
  if (!p) return '***';
  const d = p.replace(/\D/g, '');
  return d.length < 6 ? '***' : d.slice(0,3) + '***' + d.slice(-3);
};

// Get unique phones
const uniquePhones = [...new Set(flat.map(r => r.phone_number))];

// Build SMS body
const smsBody = `🌿 EcoVoice Update: Your community scored an average of ${avgScore} today! User ${maskPhone(topPhone)} is leading the street. Tip for tomorrow: separating wet waste earns you +10 points! ♻️`;

return uniquePhones.map(phone => ({
  json: { phone, message: smsBody, avgScore, topPhone: maskPhone(topPhone) }
}));
